PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "schema_migrations" ("version" varchar NOT NULL PRIMARY KEY);
CREATE TABLE IF NOT EXISTS "ar_internal_metadata" ("key" varchar NOT NULL PRIMARY KEY, "value" varchar, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE TABLE IF NOT EXISTS "users" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "email" varchar DEFAULT '' NOT NULL, "encrypted_password" varchar DEFAULT '' NOT NULL, "reset_password_token" varchar, "reset_password_sent_at" datetime(6), "remember_created_at" datetime(6), "role" varchar DEFAULT 'seller', "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE TABLE IF NOT EXISTS "providers" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar, "contact_name" varchar, "email" varchar, "phone" varchar, "notes" text, "active" boolean DEFAULT 1, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "category" varchar DEFAULT 'externo');
CREATE TABLE IF NOT EXISTS "variant_types" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "description" text, "active" boolean DEFAULT 1 NOT NULL, "position" integer DEFAULT 0);
CREATE TABLE IF NOT EXISTS "product_variant_rules" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "product_id" integer NOT NULL, "variant_type_id" integer NOT NULL, "position" integer, "required" boolean DEFAULT 1, "separator" varchar DEFAULT '-', "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "label" varchar, CONSTRAINT "fk_rails_5ed2da4178"
FOREIGN KEY ("product_id")
  REFERENCES "products" ("id")
, CONSTRAINT "fk_rails_8dee365b53"
FOREIGN KEY ("variant_type_id")
  REFERENCES "variant_types" ("id")
);
CREATE TABLE IF NOT EXISTS "families" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar, "description" text, "active" boolean DEFAULT 1, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE TABLE IF NOT EXISTS "family_variant_rules" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "family_id" integer NOT NULL, "variant_type_id" integer NOT NULL, "position" integer, "required" boolean DEFAULT 1, "separator" varchar DEFAULT '-', "label" varchar, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, CONSTRAINT "fk_rails_5513c4df3b"
FOREIGN KEY ("family_id")
  REFERENCES "families" ("id")
, CONSTRAINT "fk_rails_09a39e751d"
FOREIGN KEY ("variant_type_id")
  REFERENCES "variant_types" ("id")
);
CREATE TABLE IF NOT EXISTS "products" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar, "base_code" varchar, "description" text, "active" boolean DEFAULT 1, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "family_id" integer, CONSTRAINT "fk_rails_fdc6600f93"
FOREIGN KEY ("family_id")
  REFERENCES "families" ("id")
);
CREATE TABLE IF NOT EXISTS "variants" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "variant_type_id" integer NOT NULL, "provider_id" integer, "name" varchar, "code" varchar, "provider_sku" varchar, "active" boolean DEFAULT 1, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "display_name" varchar, "technical_description" text, CONSTRAINT "fk_rails_cb236fcb21"
FOREIGN KEY ("provider_id")
  REFERENCES "providers" ("id")
, CONSTRAINT "fk_rails_8fba028043"
FOREIGN KEY ("variant_type_id")
  REFERENCES "variant_types" ("id")
);
CREATE TABLE IF NOT EXISTS "purchase_orders" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "provider_id" integer NOT NULL, "number" varchar, "issued_date" date, "delivery_deadline" date, "status" varchar, "notes" text, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, CONSTRAINT "fk_rails_cd62199571"
FOREIGN KEY ("provider_id")
  REFERENCES "providers" ("id")
);
CREATE TABLE IF NOT EXISTS "purchase_order_items" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "purchase_order_id" integer NOT NULL, "variant_id" integer NOT NULL, "quantity" decimal, "unit" varchar, "unit_cost" decimal, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "description_override" varchar, CONSTRAINT "fk_rails_f247068a39"
FOREIGN KEY ("purchase_order_id")
  REFERENCES "purchase_orders" ("id")
, CONSTRAINT "fk_rails_9de7f6c7be"
FOREIGN KEY ("variant_id")
  REFERENCES "variants" ("id")
);
CREATE TABLE IF NOT EXISTS "properties" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar NOT NULL, "active" boolean DEFAULT 1, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE TABLE IF NOT EXISTS "property_values" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "property_id" integer NOT NULL, "value" varchar NOT NULL, "active" boolean DEFAULT 1, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, CONSTRAINT "fk_rails_0c2d25978c"
FOREIGN KEY ("property_id")
  REFERENCES "properties" ("id")
);
CREATE TABLE IF NOT EXISTS "variant_properties" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "variant_id" integer NOT NULL, "property_value_id" integer NOT NULL, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, CONSTRAINT "fk_rails_55586a9c11"
FOREIGN KEY ("variant_id")
  REFERENCES "variants" ("id")
, CONSTRAINT "fk_rails_5b4550cdc0"
FOREIGN KEY ("property_value_id")
  REFERENCES "property_values" ("id")
);
CREATE TABLE IF NOT EXISTS "product_variant_prices" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "product_id" integer NOT NULL, "variant_id" integer NOT NULL, "price" decimal(15,2), "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, CONSTRAINT "fk_rails_a2724e116c"
FOREIGN KEY ("product_id")
  REFERENCES "products" ("id")
, CONSTRAINT "fk_rails_bc4865a54b"
FOREIGN KEY ("variant_id")
  REFERENCES "variants" ("id")
);
CREATE TABLE IF NOT EXISTS "compatibilities" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "variant_id" integer NOT NULL, "compatible_id" integer NOT NULL, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL, "compatible_type" varchar DEFAULT 'Variant', CONSTRAINT "fk_rails_67a32400d5"
FOREIGN KEY ("variant_id")
  REFERENCES "variants" ("id")
);
CREATE TABLE IF NOT EXISTS "code_settings" ("id" integer PRIMARY KEY AUTOINCREMENT NOT NULL, "name" varchar DEFAULT 'Configuración General', "max_chars_per_line" integer DEFAULT 30, "max_lines" integer DEFAULT 5, "default_separator" varchar DEFAULT '-', "show_stock_sala" boolean DEFAULT 1, "stock_sala_label" varchar DEFAULT 'STOCK DE SALA', "use_prefixes" boolean DEFAULT 1, "prefix_length" integer DEFAULT 3, "created_at" datetime(6) NOT NULL, "updated_at" datetime(6) NOT NULL);
CREATE UNIQUE INDEX "index_users_on_email" ON "users" ("email");
CREATE UNIQUE INDEX "index_users_on_reset_password_token" ON "users" ("reset_password_token");
CREATE INDEX "index_product_variant_rules_on_product_id" ON "product_variant_rules" ("product_id");
CREATE INDEX "index_product_variant_rules_on_variant_type_id" ON "product_variant_rules" ("variant_type_id");
CREATE INDEX "index_family_variant_rules_on_family_id" ON "family_variant_rules" ("family_id");
CREATE INDEX "index_family_variant_rules_on_variant_type_id" ON "family_variant_rules" ("variant_type_id");
CREATE INDEX "index_products_on_family_id" ON "products" ("family_id");
CREATE INDEX "index_variants_on_variant_type_id" ON "variants" ("variant_type_id");
CREATE INDEX "index_variants_on_provider_id" ON "variants" ("provider_id");
CREATE INDEX "index_purchase_orders_on_provider_id" ON "purchase_orders" ("provider_id");
CREATE INDEX "index_purchase_order_items_on_purchase_order_id" ON "purchase_order_items" ("purchase_order_id");
CREATE INDEX "index_purchase_order_items_on_variant_id" ON "purchase_order_items" ("variant_id");
CREATE UNIQUE INDEX "index_properties_on_name" ON "properties" ("name");
CREATE INDEX "index_property_values_on_property_id" ON "property_values" ("property_id");
CREATE UNIQUE INDEX "index_property_values_on_property_id_and_value" ON "property_values" ("property_id", "value");
CREATE INDEX "index_variant_properties_on_variant_id" ON "variant_properties" ("variant_id");
CREATE INDEX "index_variant_properties_on_property_value_id" ON "variant_properties" ("property_value_id");
CREATE UNIQUE INDEX "index_variant_properties_on_variant_id_and_property_value_id" ON "variant_properties" ("variant_id", "property_value_id");
CREATE INDEX "index_product_variant_prices_on_product_id" ON "product_variant_prices" ("product_id");
CREATE INDEX "index_product_variant_prices_on_variant_id" ON "product_variant_prices" ("variant_id");
CREATE INDEX "index_compatibilities_on_variant_id" ON "compatibilities" ("variant_id");
CREATE INDEX "index_compatibilities_on_compatible_id" ON "compatibilities" ("compatible_id");
CREATE INDEX "index_compatibilities_on_compatible_type_and_compatible_id" ON "compatibilities" ("compatible_type", "compatible_id");
CREATE UNIQUE INDEX "index_compatibilities_unique_composite" ON "compatibilities" ("variant_id", "compatible_id", "compatible_type");
COMMIT;
